sql:
SELECT *
FROM rules
WHERE percent_suppressed = (SELECT MAX(percent_suppressed) FROM rules);

SELECT rule_id, title
FROM rules
WHERE rank >= 2000;

SELECT name, rank
FROM rules
WHERE rank > 1000 AND triggered > 100;

SELECT rule_id, name, triggered, suppressed
FROM rules
WHERE default_state = '1' AND triggered > 0 AND suppressed > 0;

SELECT * 
FROM rules 
WHERE rule_id = '001' AND triggered > 5;

SELECT rules.title, categories.category_name
FROM rules
INNER JOIN categories ON rules.category = categories.category_id;

SELECT name, revised_priority
FROM rules
WHERE suppressed > (
    SELECT AVG(triggered)
    FROM rules
);

external_knowledge:
- "quite a bit" refers to a rule being triggered 100 or more times;
- "not often dismissed" indicates that the rule has been suppressed fewer than 10 times;
- "importance" is synonymous with the rank of a rule;
- "average among highly active rules" refers to the average rank of rules that have been triggered frequently (at least 100 times).
